import React, { useContext, useState, useEffect } from "react";
import { Link, useNavigate, useLocation } from "react-router-dom";
import { AuthContext } from "../../context/AuthContext";
import { CartContext } from "../../context/CartContext";
import { productAPI, categoryAPI } from "../../api";
import "../../index.css";

const Header = () => {
  const { user, logout } = useContext(AuthContext);
  const { cartItems } = useContext(CartContext);
  const navigate = useNavigate();
  const location = useLocation();

  const [searchTerm, setSearchTerm] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("all");
  const [categories, setCategories] = useState([]);
  const [suggestions, setSuggestions] = useState([]);
  const [showSuggestions, setShowSuggestions] = useState(false);

  const cartCount = cartItems?.reduce((t, i) => t + (i.quantity || 1), 0) || 0;

  useEffect(() => {
    fetchCategories();
    const params = new URLSearchParams(location.search);
    setSearchTerm(params.get("q") || "");
    setSelectedCategory(params.get("category") || "all");
    // cleanup suggestion timer if any
    return () => clearTimeout(window.headerSearchTimeout);
  }, [location.search]);

  const fetchCategories = async () => {
    try {
      const res = await categoryAPI.getCategories();
      if (res.data && Array.isArray(res.data)) setCategories(res.data);
    } catch (err) {
      console.error("Header fetchCategories:", err);
      // fallback small list
      setCategories([
        { _id: "hoa-hong", name: "Hoa hồng", slug: "hoa-hong" },
        { _id: "hoa-sinh-nhat", name: "Hoa sinh nhật", slug: "hoa-sinh-nhat" },
      ]);
    }
  };

  const fetchSuggestions = async (term) => {
    if (!term || term.length < 2) return setSuggestions([]);
    try {
      const res = await productAPI.getSearchSuggestions(term);
      setSuggestions(res.data?.suggestions || []);
    } catch {
      setSuggestions([]);
    }
  };

  const handleSearchInputChange = (e) => {
    const v = e.target.value;
    setSearchTerm(v);
    clearTimeout(window.headerSearchTimeout);
    window.headerSearchTimeout = setTimeout(() => {
      fetchSuggestions(v);
      setShowSuggestions(v.length > 0);
    }, 250);
  };

  const submitSearch = (e) => {
    e.preventDefault();
    const params = new URLSearchParams();
    if (searchTerm.trim()) params.set("q", searchTerm.trim());
    if (selectedCategory !== "all") params.set("category", selectedCategory);
    navigate(`/product${params.toString() ? `?${params.toString()}` : ""}`);
    setShowSuggestions(false);
  };

  return (
    <>
      {/* Top small bar */}
      <div className="topbar" style={{ background: "#faf8f6", padding: "6px 10%" }}>
        <div style={{ display: "flex", justifyContent: "space-between" }}>
          <div style={{ fontStyle: "italic" }}>DDT Flower Shop</div>
          <div style={{ display: "flex", gap: 12 }}>
            {user ? (
              <>
                <Link to="/profile">{user.name}</Link>
                {user.role === "admin" && <Link to="/admin/dashboard">Quản trị</Link>}
                <button onClick={logout} className="linkish">Đăng xuất</button>
              </>
            ) : (
              <Link to="/login">Tài khoản</Link>
            )}
          </div>
        </div>
      </div>

      {/* Main header */}
      <header className="site-header" style={{ background: "#fff", borderBottom: "1px solid #eee" }}>
        <div style={{ display: "flex", alignItems: "center", padding: "18px 10%", gap: 20 }}>
          <Link to="/" style={{ display: "flex", alignItems: "center", gap: 12 }}>
            <img src="/DTP.png" alt="logo" style={{ height: 60, borderRadius: 999 }} />
            <span style={{ fontFamily: "Playfair Display, serif", fontSize: 26 }}>DDT Flower</span>
          </Link>

          <form onSubmit={submitSearch} style={{ flex: 1, maxWidth: 720 }}>
            <div style={{ display: "flex", borderRadius: 25, overflow: "hidden", border: "1px solid #ddd" }}>
              <select
                value={selectedCategory}
                onChange={(e) => setSelectedCategory(e.target.value)}
                style={{ border: "none", padding: "10px 12px", background: "#fff" }}
              >
                <option value="all">Tất cả</option>
                {categories.map((c) => (
                  <option key={c._id} value={c.slug}>{c.name}</option>
                ))}
              </select>
              <input
                value={searchTerm}
                onChange={handleSearchInputChange}
                placeholder="Tìm kiếm hoa..."
                style={{ flex: 1, border: "none", padding: "10px 12px" }}
                onFocus={() => setShowSuggestions(searchTerm.length > 0)}
              />
              <button type="submit" style={{ background: "#e06c7f", color: "#fff", width: 44, border: "none" }}>
                🔍
              </button>
            </div>

            {/* suggestions */}
            {showSuggestions && suggestions.length > 0 && (
              <div style={{ background: "#fff", border: "1px solid #eee", marginTop: 4, borderRadius: 6, maxHeight: 220, overflowY: "auto" }}>
                {suggestions.map((s, idx) => (
                  <div key={idx} onClick={() => { setSearchTerm(s); setShowSuggestions(false); navigate(`/product?q=${encodeURIComponent(s)}`); }} style={{ padding: 10, cursor: "pointer", borderBottom: "1px solid #f2f2f2" }}>
                    {s}
                  </div>
                ))}
              </div>
            )}
          </form>

          <Link to="/cart" style={{ background: "#e06c7f", color: "#fff", padding: "10px 18px", borderRadius: 30, textDecoration: "none" }}>
            🛒 Giỏ hàng {cartCount > 0 && <span style={{ marginLeft: 8, background: "#333", color: "#fff", padding: "2px 8px", borderRadius: 999 }}>{cartCount}</span>}
          </Link>
        </div>
      </header>
    </>
  );
};

export default Header;
